#include <bits/stdc++.h>
using namespace std;

string makeValid(string s) {
    stack<int> st;

    for(int i = 0; i < s.length(); i++) {
        if(s[i] == '(') {
            st.push(i);
        }
        else if(s[i] == ')') {
            if(!st.empty()) {
                st.pop();
            }
            else {
                s[i] = '#';
            }
        }
    }

    while(!st.empty()) {
        s[st.top()] = '#';
        st.pop();
    }

    string result;
    for(char c : s) {
        if(c != '#') {
            result += c;
        }
    }

    return result.empty() || (result.find('(') == string::npos && 
           result.find(')') == string::npos) ? "-1" : result;
}

int main() {
    int t;
    cin >> t;
    cin.ignore();

    while(t--) {
        string s;
        getline(cin, s);
        cout << makeValid(s) << endl;
    }
    return 0;
}
